tool_input.script:
export const meta = {
  name: 'qa-semantic-search',
  description: 'Execute semantic search for QA workflow',
  phases: [
    { title: 'SemanticSearch', detail: 'Search knowledge files for relevant sections' },
    { title: 'ReadSections', detail: 'Read selected section content' }
  ]
}

phase('SemanticSearch')

const searchResult = await agent(
  `Execute the semantic search workflow described in workflows/semantic-search.md for the following query:

"Nablarch 5からNablarch 6にバージョンアップするとき、Jakarta EE 10対応でアプリケーションに影響がある変更は何か？（目的: バージョンアップしたい）"

Working directory: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6

Steps to follow:
1. Read the file at workflows/semantic-search.md to understand the workflow
2. Execute the semantic search as described in that workflow
3. For each page, record why it was selected or skipped
4. For each section, record why it was selected (high/partial) or skipped
5. Return the full results as JSON with this structure:
{
  "selected_sections": [
    {"file": "<full path>", "section_id": "<sN>", "relevance": "<high|partial>"}
  ],
  "selected_pages": [
    {"path": "<page path relative to knowledge/>", "reason": "<why selected>"}
  ],
  "excluded_pages": [
    {"path": "<page path relative to knowledge/>", "reason": "<why skipped>"}
  ],
  "excluded_sections": [
    {"file": "<full path>", "section_id": "<sN>", "reason": "<why skipped>"}
  ],
  "section_reasons": [
    {"file": "<full path>", "section_id": "<sN>", "relevance": "<high|partial>", "reason": "<why selected>"}
  ]
}`,
  {
    label: 'semantic-search',
    phase: 'SemanticSearch',
    schema: {
      type: 'object',
      properties: {
        selected_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              relevance: { type: 'string' }
            },
            required: ['file', 'section_id', 'relevance']
          }
        },
        selected_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        excluded_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        excluded_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'reason']
          }
        },
        section_reasons: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              relevance: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'relevance', 'reason']
          }
        }
      },
      required: ['selected_sections', 'selected_pages', 'excluded_pages', 'excluded_sections', 'section_reasons']
    }
  }
)

return searchResult
